async function beginVaultLogin(user){let remoteUser=null,remoteError="";state.view="vault";state.loading="vault";state.animateVault=true;state.leftCollapsed=true;state.selected=null;state.selectedObject=null;state.openMenu=null;state.sortMenu=false;clearTimeout(vaultLoadingTimer);clearTimeout(vaultEnterTimer);render();if(shouldUseRemoteLogin(user)){try{let session=user.action==="signup"&&vaultRemote.signUpWithPassword?await vaultRemote.signUpWithPassword(user.email,user.password):await vaultRemote.signInWithPassword(user.email,user.password);if(session&&session.access_token){remoteUser={id:session.user&&session.user.id,email:session.user&&session.user.email||user.email,provider:"supabase"};await importRemoteVault()}else{remoteError="Account created. Check your email if confirmation is enabled, then log in again."}}catch(err){remoteError=err.message||"Supabase login failed."}}state.user=remoteUser||{email:user.email,provider:user.provider||"password"};ensureVaultApiToken();save(S.user,state.user);render();vaultLoadingTimer=setTimeout(()=>{state.loading=null;render();vaultEnterTimer=setTimeout(()=>{state.animateVault=false;render();if(remoteError)toast((remoteUser?"":"Using local alpha. ")+remoteError)},1300)},560)}
