function getVaultApiToken(){let saved=load(S.apiToken,"");if(saved)return saved;try{let session=JSON.parse(localStorage.getItem("aplus-vault-supabase-session")||"null");if(session&&session.access_token)return session.access_token}catch(e){}return ""}
