function rightCollapsedPanel(label){return "<div class='right-mini-panel'><button class='collapse-button right-reopen' data-toggle-right title='Open "+escA(label)+"'>"+icon("expand")+"<span class='vertical-label'>"+esc(label)+"</span></button></div>"}
function resizeHandle(){return "<button class='resize-handle' data-resize-right title='Drag to resize details' aria-label='Resize detail sidebar'><span></span></button>"}
function captureMarkup(showEntry){let stats=count(),items=state.items.slice(0,6),projectList=state.projects.slice(0,3),entry=showEntry?"<div class='capture-entry-actions'><button class='primary-button capture-entry-button' data-view='vault'>"+icon("vault")+"<span>Open Workspace</span></button><button class='ghost-button capture-entry-button' data-view='moodboards'>"+icon("board")+"<span>Build Moodboard</span></button></div>":"";return "<main class='capture-page'><section class='capture-hero'><div class='capture-title-block'><h1>A+ Vault</h1><p>PREMIUM CREATIVE REFERENCE VAULT</p>"+entry+"</div><div class='capture-steps'><div class='capture-step'><span>1</span><strong>Find inspiration anywhere</strong><small>Right-click any image on the web.</small></div><div class='capture-step'><span>2</span><strong>Save with context</strong><small>Organize instantly with projects, collections, and notes.</small></div><div class='capture-step'><span>3</span><strong>Find it in your Vault</strong><small>Your item is saved to the Vault Library and added to your project.</small></div></div><div class='capture-flow-stage'>"+browserCaptureMock()+"<div class='flow-arrow'>&rarr;</div>"+capturePopupMock()+"<div class='flow-arrow'>&rarr;</div>"+vaultLibraryMock(items,projectList,stats)+"</div><div class='capture-under-note'><div class='capture-note-icon'>"+icon("compass")+"</div><div><strong>Works across any website.</strong><span>One click to save what inspires you.</span></div></div><div class='capture-benefits'><div>"+icon("layers")+"<span>Save anything that inspires you</span></div><div>"+icon("tag")+"<span>Organize with projects, collections, and tags</span></div><div>"+icon("search")+"<span>Find what you need, when you need it</span></div><div>"+icon("lock")+"<span>Private. Secure. Always yours.</span></div></div></section></main>"}
function captureView(){return shell(captureMarkup(true))}
function browserCaptureMock(){return "<article class='browser-mock'><div class='browser-bar'><span></span><span></span><span></span><div>openhouse-magazine.com/interiors/soft-modern-living</div></div><div class='browser-content'><div class='interior-scene'><img src='"+escA(svg(760,620,"<rect width='760' height='620' fill='#e7ded2'/><rect width='760' height='620' fill='#e8dfd4'/><rect x='58' y='62' width='230' height='500' rx='120' fill='#f7f3ec'/><rect x='82' y='86' width='182' height='452' rx='95' fill='#d2c5b6'/><rect x='312' y='180' width='292' height='210' rx='18' fill='#c9baaa'/><rect x='365' y='230' width='232' height='145' rx='80' fill='#f6f0e7'/><rect x='90' y='505' width='520' height='80' rx='40' fill='#d7c6b4'/><circle cx='524' cy='438' r='70' fill='#c8b59f'/><circle cx='532' cy='438' r='48' fill='#efe8dd'/><path d='M162 354c25-90 72-126 145-142' fill='none' stroke='#4a443c' stroke-width='6'/><rect x='146' y='368' width='60' height='100' rx='24' fill='#252420'/><path d='M175 252c22 36 24 79 4 116' fill='none' stroke='#383630' stroke-width='5'/><text x='622' y='220' fill='#171717' font-size='42' font-family='Georgia'>Soft</text><text x='622' y='266' fill='#171717' font-size='42' font-family='Georgia'>Modern</text>"))+"' alt='Soft modern living reference'></div><aside><h3>Soft Modern Living</h3><p>A study in balance, natural light, layered textures, and timeless materials create a quietly sophisticated interior.</p><small>Photography by Luca Moretti</small></aside><div class='context-menu-mock'><button>Open image in new tab</button><button>Save image as...</button><button>Copy image</button><button>Copy image address</button><button>Search image with Google</button><button class='save-context' data-open>"+icon("plus")+" Save to A+ Vault</button><button>Inspect</button></div></div></article>"}
function capturePopupMock(){return "<article class='capture-popup-mock'><header><div class='popup-mark'>A<sup>+</sup></div><strong>Save to A+ Vault</strong><button>×</button></header><div class='popup-preview'>"+browserThumb()+"</div><label>Title<input value='Soft modern living room with arched window' readonly></label><label>Project<select><option>No project</option><option selected>Aplus1 Branding</option><option>WP Catalog</option><option>Blacksmith Ads</option></select></label><label>Collection <span>(optional)</span><select><option selected>Vault Library</option><option>Interior References</option></select></label><label>Note <span>(optional)</span><textarea placeholder='Add a note...' readonly></textarea></label><button class='popup-save' data-open>Save</button><p>"+icon("lock")+" If no project is selected, this item will still be saved to your Vault Library.</p></article>"}
function vaultLibraryMock(items,projects,stats){return "<article class='vault-mock'><aside><div class='mock-logo'>A<sup>+</sup> Vault</div><button class='active'>"+icon("vault")+" Vault Library</button><button>"+icon("project")+" Projects</button><button>"+icon("board")+" Moodboards</button><button>"+icon("collections")+" Collections</button><button>"+icon("tag")+" Tags</button><button>"+icon("archive")+" Archive</button><hr><button>"+icon("settings")+" Settings</button><button>"+icon("import")+" Import</button></aside><section><header><label class='mock-search'>"+icon("search")+"<input placeholder='Search your vault...' readonly></label><div>"+icon("filter")+icon("bell")+"<span class='mock-avatar'>A<sup>+</sup></span></div></header><div class='mock-library-head'><h2>Vault Library <span>"+stats.total+"</span></h2><div class='mock-chips'><span class='active'>All</span><span>Images</span><span>Videos</span><span>Links</span><span>Docs</span></div></div><div class='mock-grid'>"+items.map(mockVaultCard).join("")+"</div></section><aside class='mock-success'><div class='success-check'>"+icon("check")+"</div><h3>Saved to<br>Vault Library</h3><p>Added to Project:</p><strong>Aplus1 Branding</strong><button data-view='vault'>View in Library</button><a data-view='project'>Open Project</a><div class='mock-side-list'><h4>Projects</h4>"+projects.map(p=>"<span>"+esc(p.name)+"<small>"+p.boards.length+" board</small></span>").join("")+"</div></aside></article>"}
function browserThumb(){return "<div class='mini-interior'><span></span><span></span><span></span></div>"}
function mockVaultCard(i){let a=i.analysis||{},colors=(a.colors||[]).slice(0,2);return "<div class='mock-vault-card'>"+media(i)+"<strong>"+esc(i.title)+"</strong><small>"+esc(i.type==="link"?host(i.sourceUrl):(i.sourceUrl||"Private note"))+"</small><div>"+colors.map(c=>"<i style='background:"+c+"'></i>").join("")+"<span>"+esc(projectLabel(i)||"Aplus1 Branding")+"</span></div></div>"}
function vaultView(){let items=filtered(),sel=state.selected?state.items.find(i=>i.id===state.selected):null,stats=count(),realCols=state.cols.filter(c=>!c.system),cls="workspace"+(state.leftCollapsed?" left-collapsed":"")+(sel?"":" detail-closed")+(state.animateVault?" vault-enter":"");return shell("<div class='"+cls+"' style='--right-width:"+state.rightWidth+"px'><aside class='rail'>"+sideNav(vaultStatsBlock(stats,realCols))+sidebarMain()+"</aside><main class='main'><section class='vault-command-row'><div class='filter-chips'>"+["all","image","video","link","note"].map(chip).join("")+"</div>"+vaultSortControl()+"</section>"+(items.length?vaultItemsMarkup(items):empty())+"</main>"+(sel?"<aside class='drawer open'>"+resizeHandle()+detail(sel)+"</aside>":"")+"</div>")}
function vaultItemsMarkup(items){if(state.col==="all"&&state.sortBy==="saved_new")return "<section class='vault-groups'>"+timeGroups(items).map(g=>g.items.length?"<section class='vault-time-group'><h2>"+esc(g.label)+"</h2><div class='masonry'>"+g.items.map((i,idx)=>card(i,idx)).join("")+"</div></section>":"").join("")+"</section>";return "<section class='masonry'>"+items.map(card).join("")+"</section>"}
function timeGroups(items){let now=Date.now(),week=7*24*60*60*1000,monthStart=new Date();monthStart.setDate(1);monthStart.setHours(0,0,0,0);let groups=[{label:"Recent 7 Days",items:[]},{label:"This Month",items:[]},{label:"Older",items:[]}];items.forEach(i=>{let t=Number(i.createdAt)||0;if(t>=now-week)groups[0].items.push(i);else if(t>=monthStart.getTime())groups[1].items.push(i);else groups[2].items.push(i)});return groups.filter(g=>g.items.length)}
function projectView(){let p=project(),stats=count(),realCols=state.cols.filter(c=>!c.system),cols=projectCollectionIds(p).map(id=>state.cols.find(c=>c.id===id)).filter(Boolean),boards=p.boards||[],items=projectItems(p),cls="workspace overview-workspace detail-closed"+(state.leftCollapsed?" left-collapsed":"");return shell("<div class='"+cls+"'><aside class='rail'>"+sideNav(vaultStatsBlock(stats,realCols))+sidebarMain()+"</aside><main class='main overview-main'><section class='page-head'><div><span class='section-label'>Project workspace</span><h1>"+esc(p.name)+"</h1><p>Project คือพื้นที่รวม objects, collections และ moodboards ของงานนี้ ก่อนเลือกบอร์ดไปจัด canvas.</p></div><button class='primary-button' data-newboard='"+p.id+"'>"+icon("plus")+"<span>New Moodboard</span></button></section><section class='project-overview-summary'><article><strong>"+items.length+"</strong><span>Project objects</span></article><article><strong>"+cols.length+"</strong><span>Collections</span></article><article><strong>"+boards.length+"</strong><span>Moodboards</span></article></section><section class='overview-split'><article class='overview-panel'><div class='overview-panel-head'><h2>Collections in this project</h2></div><div class='overview-list'>"+(cols.length?cols.map(c=>projectCollectionRow(p,c)).join(""):"<div class='empty-list-card'>No custom collections in this project yet.</div>")+"</div></article><article class='overview-panel'><div class='overview-panel-head'><h2>Moodboards in this project</h2><button class='mini-button' data-newboard='"+p.id+"'>+</button></div><div class='overview-list'>"+(boards.length?boards.map(b=>projectMoodboardRow(p,b)).join(""):"<div class='empty-list-card'>No moodboards yet. Create the first one.</div>")+"</div></article></section></main></div>")}
function projectsView(){let stats=count(),realCols=state.cols.filter(c=>!c.system),cls="workspace overview-workspace detail-closed"+(state.leftCollapsed?" left-collapsed":"");return shell("<div class='"+cls+"'><aside class='rail'>"+sideNav(vaultStatsBlock(stats,realCols))+sidebarMain()+"</aside><main class='main overview-main'><section class='page-head'><div><h1>Projects</h1><p>Project คือพื้นที่รวม collections และ moodboards ของงานแต่ละชิ้น เลือกโปรเจกต์เพื่อดูรายการทั้งหมดก่อนเข้า board.</p></div><button class='primary-button' data-newproject>"+icon("plus")+"<span>New Project</span></button></section>"+(state.projects.length?"<section class='project-index-grid'>"+state.projects.map(projectCard).join("")+"</section>":"<section class='empty-state'><div><h2>No projects yet.</h2><p>Create a project to gather collections and moodboards around one job.</p><button class='primary-button' data-newproject>Create Project</button></div></section>")+"</main></div>")}
function moodboardsView(){let stats=count(),realCols=state.cols.filter(c=>!c.system),pairs=allBoards(),cls="workspace overview-workspace detail-closed"+(state.leftCollapsed?" left-collapsed":"");return shell("<div class='"+cls+"'><aside class='rail'>"+sideNav(vaultStatsBlock(stats,realCols))+sidebarMain()+"</aside><main class='main overview-main'><section class='page-head'><div><h1>Moodboards</h1><p>รวม moodboard ทุกโปรเจกต์ เลือกเปิด canvas เมื่อพร้อมทำงาน หรือสร้าง แก้ชื่อ และลบบอร์ดได้จากหน้านี้.</p></div><button class='primary-button' data-newboard='"+state.activeProject+"'>"+icon("plus")+"<span>New Moodboard</span></button></section>"+(pairs.length?"<section class='moodboard-index-grid'>"+pairs.map(moodboardCard).join("")+"</section>":"<section class='empty-state'><div><h2>No moodboards yet.</h2><p>Create your first board, then pull objects from Vault Library into it.</p><button class='primary-button' data-newboard='"+state.activeProject+"'>Create Moodboard</button></div></section>")+"</main></div>")}
function projectCollectionRow(p,c){let items=projectItems(p).filter(i=>(i.collectionIds||[]).includes(c.id)),fallback=itemsForCollection(c.id).length;return "<article class='list-card collection-list-card'><button class='list-card-main' data-col='"+c.id+"'>"+icon("collection")+"<span><strong>"+esc(c.name)+"</strong><small>"+(items.length||fallback)+" objects</small></span></button><div class='list-card-actions'><button data-editcol='"+c.id+"' title='Rename'>"+icon("edit")+"</button><button class='danger-link' data-delcol='"+c.id+"' title='Delete'>"+icon("trash")+"</button></div></article>"}
function projectMoodboardRow(p,b){return "<article class='list-card moodboard-list-card'><button class='list-card-main' data-openboard='"+p.id+":"+b.id+"'>"+moodboardPreview(b)+"<span><strong>"+esc(b.name)+"</strong><small>"+((b.objects||[]).length)+" objects · "+esc(p.name)+"</small></span></button><div class='list-card-actions'><button data-editboard='"+p.id+":"+b.id+"' title='Rename'>"+icon("edit")+"</button><button class='danger-link' data-delboard='"+p.id+":"+b.id+"' title='Delete'>"+icon("trash")+"</button></div></article>"}
function moodboardCard(pair){let p=pair.project,b=pair.board;return "<article class='moodboard-index-card'><button class='moodboard-card-open' data-openboard='"+p.id+":"+b.id+"'>"+moodboardPreview(b)+"<span><strong>"+esc(b.name)+"</strong><small>"+esc(p.name)+" · "+((b.objects||[]).length)+" objects</small></span></button><div class='moodboard-card-actions'><button data-openboard='"+p.id+":"+b.id+"'>Open</button><button data-editboard='"+p.id+":"+b.id+"'>Edit</button><button class='danger-link' data-delboard='"+p.id+":"+b.id+"'>Delete</button></div></article>"}
function moodboardPreview(b){let objs=(b.objects||[]).slice(0,6);return "<div class='moodboard-preview'>"+(objs.length?objs.map((o,idx)=>"<i class='preview-obj p"+(idx%6)+"' style='background:"+previewColor(o)+"'></i>").join(""):"<i class='preview-empty'></i><i class='preview-empty two'></i><i class='preview-empty three'></i>")+"</div>"}
function boardView(){let p=project(),b=board(),obj=selectedObj(),items=filtered(),cls="board-workspace"+(state.leftCollapsed?" left-collapsed":"")+(state.rightCollapsed?" right-collapsed":""),right=state.rightCollapsed?rightCollapsedPanel("Inspector"):("<div class='detail-header'><span class='status-pill'>Moodboard</span><button class='icon-button drawer-close' data-toggle-right title='Close inspector'>"+icon("close")+"</button></div><h2>Selected Object</h2>"+(obj?objectInspector(obj):"<p class='inspector-empty'>Select an object, drag from the vault, or add a text object.</p>")+"<button class='primary-button wide' data-board-save>Save Board</button><button class='ghost-button wide' data-share>Share Link</button>");return shell("<div class='"+cls+"' style='--right-width:"+state.rightWidth+"px'><aside class='project-rail'>"+sideNav()+sidebarMain()+"</aside><aside class='library-rail'><div class='rail-heading'><h2>Vault Library</h2><button class='mini-button' data-board-save>Save</button></div><div class='board-filter'><select data-lib-filter><option value='all'>All Items</option><option value='image'>Images</option><option value='video'>Videos</option><option value='link'>Links</option><option value='note'>Notes</option></select></div><div class='library-grid'>"+items.map(libraryCard).join("")+"</div><p class='library-hint'>Drag items to canvas to add</p></aside><main class='board-main'>"+projectContextPanel(p)+"<section class='board-title-row'><div><input class='board-title' data-board-title value='"+escA(b.name)+"'><p>Project: "+esc(p.name)+"</p></div><div class='board-toolbar'><button class='ghost-button' data-addtext>Add Text</button><button class='ghost-button' data-addfromvault>Add From Vault</button><button class='ghost-button' data-export>Export</button><button class='ghost-button' data-grid>Grid</button></div></section><section class='canvas-wrap'><div class='mood-canvas' data-canvas>"+b.objects.map(boardObject).join("")+"</div></section></main><aside class='inspector "+(state.rightCollapsed?"mini":"")+"'>"+(state.rightCollapsed?right:resizeHandle()+right)+"</aside></div>")}
function collectionsView(){let stats=count(),realCols=state.cols.filter(c=>!c.system),cls="workspace overview-workspace detail-closed"+(state.leftCollapsed?" left-collapsed":"");return shell("<div class='"+cls+"'><aside class='rail'>"+sideNav(vaultStatsBlock(stats,realCols))+sidebarMain()+"</aside><main class='main overview-main'><section class='page-head'><div><h1>Collections</h1><p>Collections คือคลังแยกหมวดจาก Vault Library ใช้จัด references ตามหมวด สไตล์ ลูกค้า หรือแคมเปญ โดย object ยังอยู่ในคลังกลางเสมอ.</p></div><button class='primary-button' data-newcol>"+icon("plus")+"<span>New Collection</span></button></section><section class='collection-overview-grid'>"+state.cols.filter(c=>!c.system).map(collectionCard).join("")+"</section></main></div>")}
function collectionCard(c){let items=itemsForCollection(c.id),custom=!c.system,types=typeCounts(items);return "<article class='collection-card "+(state.col===c.id?"active":"")+"'><button class='collection-card-main' data-col='"+c.id+"'>"+icon(c.system?"all":"collection")+"<span><strong>"+esc(c.name)+"</strong><small>"+items.length+" objects</small></span></button><div class='collection-type-row'><span>"+types.image+" images</span><span>"+types.video+" videos</span><span>"+types.link+" links</span><span>"+types.note+" notes</span></div>"+(custom?"<div class='collection-card-actions'><button data-editcol='"+c.id+"'>"+icon("edit")+"<span>Edit</span></button><button class='danger-link' data-delcol='"+c.id+"'>"+icon("trash")+"<span>Delete</span></button></div>":"<p class='system-note'>System collection</p>")+"</article>"}
function projectCard(p){let boards=p.boards||[],cols=projectCollectionIds(p).map(id=>state.cols.find(c=>c.id===id)).filter(Boolean),items=projectItems(p),first=boards[0];return "<article class='project-index-card "+(state.activeProject===p.id?"active":"")+"'><button class='project-card-open' data-project='"+p.id+"'>"+moodboardPreview(first||{objects:[]})+"<span><strong>"+esc(p.name)+"</strong><small>"+items.length+" objects · "+boards.length+" board"+(boards.length===1?"":"s")+" · "+cols.length+" collection"+(cols.length===1?"":"s")+"</small></span></button><div class='project-card-groups'><div><b>Collections</b><p>"+(cols.length?cols.slice(0,3).map(c=>esc(c.name)).join(", "):"No custom collections yet")+"</p></div><div><b>Moodboards</b><p>"+(boards.length?boards.slice(0,3).map(b=>esc(b.name)).join(", "):"No moodboards yet")+"</p></div></div><div class='moodboard-card-actions'><button data-project='"+p.id+"'>Open</button><button data-newboard='"+p.id+"'>New board</button><button data-editproject='"+p.id+"'>Rename</button><button data-delproject='"+p.id+"'>Delete</button></div></article>"}
function profileView(){let stats=count(),realCols=state.cols.filter(c=>!c.system),s=storageBreakdown(),email=state.user&&state.user.email||"creative@aplus.local",cls="workspace profile-workspace"+(state.leftCollapsed?" left-collapsed":"")+" detail-closed";return shell("<div class='"+cls+"'><aside class='rail'>"+sideNav(vaultStatsBlock(stats,realCols))+sidebarMain()+"</aside><main class='main profile-main'><section class='page-head'><div><h1>Profile & Storage</h1><p>Manage login, privacy, data controls, and see how the 1 GB Vault storage is being used.</p></div></section><section class='profile-grid'><article class='settings-card'><h2>Login</h2><form class='profile-form' data-profile><label>Email<input name='email' type='email' value='"+escA(email)+"'></label><label>Password<input name='password' type='password' value='aplusvault'></label><button class='primary-button'>Save Login</button></form><button class='google-button profile-google' data-google-login>"+icon("google")+"<span>Continue with Google</span></button><button class='ghost-button wide' data-logout>Log out</button></article><article class='settings-card storage-card'><h2>Storage</h2><div class='storage-meter'><strong>"+formatBytes(s.total)+"</strong><span>of 1 GB used</span><i><b style='width:"+Math.min(100,s.total/s.limit*100).toFixed(2)+"%'></b></i></div><div class='storage-breakdown'>"+storageRows(s).join("")+"</div></article><article class='settings-card extension-card'><h2>Extension sync</h2><p>Paste this token into the Chrome extension popup under <strong>Alpha API Token</strong>. API Base should stay <code>https://aplus-vault.vercel.app</code>.</p><div class='extension-token-box'><code data-extension-token>"+esc(getVaultApiToken()||"Log in to generate a token")+"</code></div><button type='button' class='primary-button wide' data-copy-extension-token>Copy extension token</button><button type='button' class='ghost-button wide' data-regenerate-extension-token>Refresh token</button><a class='ghost-button wide' href='./demo.html' target='_blank' rel='noreferrer'>Demo setup guide</a></article><article class='settings-card data-card'><h2>Your data</h2><p>Download a copy of your Vault Library, collections, projects, moodboards, and capture metadata stored in this browser.</p><button type='button' class='primary-button wide' data-export-vault>Export my data</button><button type='button' class='ghost-button wide' data-clear-vault>Clear local Vault data</button><button type='button' class='ghost-button wide danger-button' data-delete-account>Delete account / request deletion</button></article><article class='settings-card privacy-card'><h2>Privacy & Legal</h2><p>Your references are private by default. You own your content. Saving a reference does not grant usage rights.</p><div class='legal-link-list'><a href='./legal.html#privacy' target='_blank' rel='noreferrer'>Privacy Notice</a><a href='./legal.html#data-rights' target='_blank' rel='noreferrer'>Export & Deletion</a><a href='./legal.html#copyright' target='_blank' rel='noreferrer'>Copyright Report</a><a href='./legal.html#ai' target='_blank' rel='noreferrer'>AI Processing</a><a href='./legal.html#security' target='_blank' rel='noreferrer'>Security</a></div></article></section></main></div>")}
function brand(){return "<div class='brand'><div class='brand-mark'>A+</div><div><p class='brand-title'>A+ Vault</p><p class='brand-subtitle'>You Create, We Connect</p></div></div>"}
function saveActionIcon(){return "<img class='save-action-icon' src='assets/vault-save-icon-128.png' alt='' aria-hidden='true'>"}
function chip(t){let name=t==="all"?"All":L[t]+"s";return "<button class='chip "+(state.type===t?"active":"")+"' data-type='"+t+"'><span class='chip-icon'>"+icon(iconForType(t))+"</span><span>"+name+"</span></button>"}
function sortOptions(){return[["saved_new","Newest saved","Pinned first, then latest objects"],["saved_old","Oldest saved","Pinned first, then oldest objects"],["color","Main color","Arrange by primary color"],["keyword","Keyword","Arrange by first keyword"],["style","Style","Mood / visual language"],["category","Category","Furniture, art, UI, branding"]]}
function sortLabel(){let found=sortOptions().find(o=>o[0]===state.sortBy)||sortOptions()[0];return found[1]}
function vaultSortControl(){return "<div class='vault-sort'><button class='sort-trigger "+(state.sortMenu?"active":"")+"' data-sorttoggle title='Filter and sort objects' aria-label='Filter and sort objects'>"+icon("filter")+"<span>"+esc(sortLabel())+(activeFilterCount()?" · "+activeFilterCount()+" filter"+(activeFilterCount()>1?"s":""):"")+"</span></button>"+(state.sortMenu?"<div class='sort-popover' role='menu'><div class='sort-section'><span>Sort</span>"+sortOptions().map(o=>"<button class='"+(state.sortBy===o[0]?"active":"")+"' data-sortby='"+o[0]+"'><strong>"+esc(o[1])+"</strong><small>"+esc(o[2])+"</small></button>").join("")+"</div><div class='sort-section compact'><span>Color family</span><div class='filter-option-row'>"+filterButtons("filtercolor",colorFilterOptions(),state.filterColor)+"</div></div><div class='sort-section compact'><span>Style</span><div class='filter-option-row'>"+filterButtons("filterstyle",styleFilterOptions(),state.filterStyle)+"</div></div><div class='sort-section compact'><span>Category</span><div class='filter-option-row'>"+filterButtons("filtercategory",categoryFilterOptions(),state.filterCategory)+"</div></div>"+(activeFilterCount()?"<button class='clear-filter-button' data-clearfilters>Clear filters</button>":"")+"</div>":"")+"</div>"}
function filterButtons(attr,options,current){return options.map(o=>"<button class='"+(current===o[0]?"active":"")+"' data-"+attr+"='"+o[0]+"'>"+esc(o[1])+"</button>").join("")}
function activeFilterCount(){return ["filterColor","filterStyle","filterCategory"].filter(k=>state[k]&&state[k]!=="all").length}
function colorFilterOptions(){return[["all","All"],["warm","Warm"],["cool","Cool"],["neutral","Neutral"],["dark","Dark"],["light","Light"],["coral","Coral"]]}
function styleFilterOptions(){return[["all","All"],["minimal","Minimal"],["premium brand","Premium"],["campaign collage","Campaign"],["digital ui","Digital UI"],["motion","Motion"]]}
function categoryFilterOptions(){return[["all","All"],["branding","Branding"],["poster","Poster"],["interior","Interior"],["furniture","Furniture"],["product","Product"],["typography","Typography"],["ui","UI"],["illustration","Illustration"],["packaging","Packaging"],["other","Other"]]}
