function sourceCredit(i){let ctx=i.captureContext||{},date=new Date(Number(i.createdAt)||Date.now()).toLocaleDateString("en-US",{year:"numeric",month:"short",day:"numeric"}),domain=host(i.sourceUrl||ctx.pageUrl||"")||"Private source";return "<div class='source-credit-card'><span class='section-label'>Source & credit</span><div><strong>"+esc(domain)+"</strong><small>Captured "+esc(date)+"</small></div><p>"+(i.sourceUrl?detailSourceLine(i):"No public source URL saved.")+"</p><em>"+esc(ctx.usageNote||"Private reference only")+"</em></div>"}
