function importHashCapture(){let hash=location.hash||"",objectPrefix="#object=";if(hash.startsWith(objectPrefix)){let objectId=decodeURIComponent(hash.slice(objectPrefix.length));if(location.pathname.startsWith("/vault")){state.selected=objectId;state.publicObject=null;state.view=state.user?"vault":"login";state.type="all";state.col="all";state.rightCollapsed=false;return}state.publicObject=objectId;state.view="object";return}let prefix="#vault-capture=";if(!hash.startsWith(prefix))return;try{let payload=decodeVaultPayload(hash.slice(prefix.length)),key="hash:"+hash.slice(prefix.length,161),seen=load(S.captures,[]);if(!seen.includes(key)){let item=itemFromCapturePayload(payload);state.items=[item].concat(state.items);state.selected=item.id;state.sortBy="saved_new";save(S.items,state.items);save(S.captures,seen.concat(key).slice(-500))}state.view=state.user?"vault":"login";history.replaceState(null,"",location.pathname+location.search)}catch(e){console.warn("Could not import Vault capture.",e)}}
