async function syncExtensionCaptures(silent){if(syncExtensionCaptures.busy)return;syncExtensionCaptures.busy=true;try{let token=getVaultApiToken(),headers=token?{Authorization:"Bearer "+token}:{},response=await fetch("/api/vault/captures",{cache:"no-store",headers});if(!response.ok)return;let data=await response.json(),rows=Array.isArray(data.items)?data.items:[],seen=load(S.captures,[]),seenSet=new Set(seen),existing=new Set(state.items.map(i=>i.id)),fresh=[];rows.forEach(row=>{let objectId=row&&row.objectId||row&&row.item&&row.item.id;if(!objectId||seenSet.has(objectId))return;let item=normalizeCapturedItem(row.item||row);if(item&&item.id&&!existing.has(item.id)){fresh.push(item);existing.add(item.id);seen.push(objectId)}});if(fresh.length){state.items=fresh.concat(state.items);state.sortBy="saved_new";save(S.items,state.items);save(S.captures,seen.slice(-500));for(let item of fresh)await syncRemoteItem(item,"create");if(!silent)toast(fresh.length===1?"Extension capture imported.":fresh.length+" extension captures imported.");render()}}catch(e){}finally{syncExtensionCaptures.busy=false}}
